# Celery task for async screenshot processing
@celery_app.task(bind=True, max_retries=3, default_retry_delay=10)
def capture_screenshot_task(self, url: str, s3_key: str, cache_key: str):
    try:
        svc = ScreenshotService(app.config)
        storage = S3Storage(s3_client, app.config["S3_BUCKET"], app.config["S3_REGION"])

        # Capture screenshot
        screenshot_data = svc.capture(url)

        # Create thumbnail
        thumbnail_data = svc.create_thumbnail(screenshot_data)

        # Upload to S3
        s3_url = storage.upload(s3_key, thumbnail_data)

        # Cache the result
        cache_data = json.dumps({
            "url": url,
            "screenshot_url": s3_url,
            "s3_key": s3_key,
            "created_at": datetime.utcnow().isoformat(),
            "status": "completed",
        })
        redis_client.setex(f"screenshot:{cache_key}", app.config["CACHE_TTL"], cache_data)

        logger.info(f"Screenshot task completed for {url}")
        return {"status": "completed", "screenshot_url": s3_url}

    except Exception as exc:
        logger.error(f"Screenshot task failed for {url}: {str(exc)}")
        # Store error status in cache
        error_data = json.dumps({
            "url": url,
            "status": "failed",
            "error": str(exc),
            "created_at": datetime.utcnow().isoformat(),
        })
        redis_client.setex(f"screenshot:{cache_key}", 300, error_data)  # Cache errors for 5 min

        raise self.retry(exc=exc)


